// Extract the OpenAI content and document ID
const items = $input.all();
let documentId = '';
let aiContent = '';

// Search through items to find what we need
for (const item of items) {
  if (item.json.documentId) {
    documentId = item.json.documentId;
  }
  if (item.json.message && item.json.message.content) {
    aiContent = item.json.message.content;
  }
}

// Return a clean object with just what we need
return [{
  json: {
    documentId: documentId,
    aiContent: aiContent
  }
}];

